// インターフェースの定義
public interface MyInterface1 {
    // デフォルトメソッドの定義
    default void myMethod() {
        System.out.println("Hello from MyInterface1");
    }
}

public interface MyInterface2 {
    // 同じ名前のデフォルトメソッドの定義
    default void myMethod() {
        System.out.println("Hello from MyInterface2");
    }
}

// 両方のインターフェースを実装するクラス
public class MyClass implements MyInterface1, MyInterface2 {
    // 明示的にデフォルトメソッドをオーバーライドする
    public void myMethod() {
        // MyInterface1のデフォルトメソッドを使用する
        MyInterface1.super.myMethod();
    }
}

// メインクラス
public class Main {
    public static void main(String[] args) {
        MyClass myClass = new MyClass();
        myClass.myMethod(); // Hello from MyInterface1
    }
}

// インターフェースの定義
public interface MyInterface1 {
    void myMethod1();
}

// MyInterface1を継承する新しいインターフェース
public interface MyInterface2 extends MyInterface1 {
    void myMethod2();
}

// インターフェースを実装するクラス
public class MyClass implements MyInterface2 {
    // MyInterface1から継承したメソッド
    public void myMethod1() {
        System.out.println("My Method 1");
    }

    // MyInterface2のメソッド
    public void myMethod2() {
        System.out.println("My Method 2");
    }
}

// メインクラス
public class Main {
    public static void main(String[] args) {
        MyClass myClass = new MyClass();
        myClass.myMethod1(); // My Method 1
        myClass.myMethod2(); // My Method 2
    }
}

// インターフェースの定義
public interface MyInterface {
    void myMethod();
}

// インターフェースを実装するクラス
public class MyClass implements MyInterface {
    public void myMethod() {
        System.out.println("Hello from MyClass");
    }
}

// インターフェースを引数に取るメソッドを持つクラス
public class MyMethodClass {
    public void callMyMethod(MyInterface mi) {
        mi.myMethod();
    }
}

// メインクラス
public class Main {
    public static void main(String[] args) {
        MyMethodClass mmc = new MyMethodClass();
        mmc.callMyMethod(new MyClass()); // Hello from MyClass
    }
}

// 関数型インターフェースの定義
@FunctionalInterface
public interface MyFunctionalInterface {
    void execute();
}

// メインクラス
public class Main {
    public static void main(String[] args) {
        // ラムダ式を使用して関数型インターフェースの実装を作成する
        MyFunctionalInterface mfi = () -> System.out.println("Hello from MyFunctionalInterface");
        mfi.execute(); // Hello from MyFunctionalInterface
    }
}

// 関数型インターフェースの定義
@FunctionalInterface
public interface MyFunctionalInterface {
    // Integer型の引数を受け取り、String型の戻り値を返す抽象メソッド
    String execute(Integer i);
}

// メインクラス
public class Main {
    public static void main(String[] args) {
        // ラムダ式を使用して関数型インターフェースの実装を作成する
        MyFunctionalInterface mfi = (i) -> "The number is " + i;
        System.out.println(mfi.execute(5)); // The number is 5
    }
}

// 関数型インターフェースの定義
@FunctionalInterface
public interface MyFunctionalInterface {
    void execute();
}

// メインクラス
public class Main {
    public static void main(String[] args) {
        // ラムダ式を使用して関数型インターフェースの実装を作成する
        MyFunctionalInterface mfi = () -> System.out.println("Hello from lambda expression");
        mfi.execute(); // Hello from lambda expression
    }
}

// Consumerの使用例
Consumer<String> consumer = (s) -> System.out.println(s);
consumer.accept("Hello from Consumer"); // Hello from Consumer

// Supplierの使用例
Supplier<String> supplier = () -> "Hello from Supplier";
System.out.println(supplier.get()); // Hello from Supplier

// Functionの使用例
Function<Integer, String> function = (i) -> "The number is " + i;
System.out.println(function.apply(5)); // The number is 5

// Predicateの使用例
Predicate<Integer> predicate = (i) -> i > 0;
System.out.println(predicate.test(5)); // true

