// 複数のインターフェースを継承するインターフェースの例
public interface Interface1 {
    default void myMethod() {
        System.out.println("Hello from Interface1");
    }
}

public interface Interface2 {
    default void myMethod() {
        System.out.println("Hello from Interface2");
    }
}

public interface MyInterface extends Interface1, Interface2 {
    // Interface1とInterface2から継承したmyMethodをオーバーライドする
    @Override
    default void myMethod() {
        Interface1.super.myMethod();
        Interface2.super.myMethod();
    }
}

public class MyClass implements MyInterface {
}

MyClass mc = new MyClass();
mc.myMethod(); // Hello from Interface1
               // Hello from Interface2
